// Evidence: http-go-performance-release-defense-worked-3
func worked_http_go_performance_release_defense_3(p95Ms int, latencyBudgetMs int, queueDepth int, queueCapacity int) (bool, bool) {
	if p95Ms < 0 || latencyBudgetMs <= 0 || queueDepth < 0 || queueCapacity <= 0 { return false, true }
	saturated := queueDepth >= queueCapacity
	release := p95Ms <= latencyBudgetMs && !saturated
	return release, saturated
}
